INSERT INTO spices (name, slug, tagline, origin_story, culinary_uses, ayurvedic_benefits, growing_season, dish_it_transforms, flavor_profile, image_url) VALUES 
('Cardamom', 'cardamom', 'The Queen of Spices', 'Originating in the lush Western Ghats of Southern India, cardamom has been traded for over 4,000 years.', 'Essential in chai, biryanis, Scandinavian baking, and Middle Eastern coffee.', 'Known to improve digestion, freshen breath, and act as a daily detox.', 'August to February', 'Cardamom Buns or Classic Indian Masala Chai', '{"sweet": 8, "spicy": 2, "earthy": 5, "floral": 9, "bitter": 1}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/cardamom.jpg'),
('Black Pepper', 'black-pepper', 'The King of Spices', 'Native to the Malabar Coast of India, it was once worth more than its weight in gold.', 'Used in almost every savory dish worldwide, from pasta to steaks to curries.', 'Contains piperine, which boosts absorption of nutrients like curcumin.', 'December to March', 'Cacio e Pepe or Peppercorn Steak', '{"sweet": 1, "spicy": 9, "earthy": 8, "floral": 1, "bitter": 4}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/pepper.jpg'),
('Cinnamon', 'cinnamon', 'Warmth and Comfort', 'True Ceylon cinnamon comes from the inner bark of a tropical evergreen tree native to Sri Lanka.', 'Baking, curries, stews, and hot beverages.', 'Rich in antioxidants and known to help regulate blood sugar levels.', 'Year-round harvest', 'Cinnamon Rolls or Moroccan Tagine', '{"sweet": 9, "spicy": 4, "earthy": 6, "floral": 2, "bitter": 1}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/cinnamon.jpg'),
('Turmeric', 'turmeric', 'The Golden Healer', 'A flowering plant of the ginger family, the roots of which are used in cooking.', 'Curries, golden milk, mustards, and cheeses.', 'Curcumin is a highly potent anti-inflammatory and antioxidant.', 'January to March', 'Golden Milk Latte or Chicken Tikka Masala', '{"sweet": 1, "spicy": 3, "earthy": 9, "floral": 2, "bitter": 7}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/turmeric.jpg'),
('Cloves', 'cloves', 'The Intense Bud', 'The aromatic flower buds of a tree in the family Myrtaceae, native to the Maluku Islands in Indonesia.', 'Garam masala, mulled wine, studding hams and onions.', 'Powerful antiseptic and mild anesthetic, traditionally used for toothaches.', 'June to August', 'Mulled Wine or Honey Glazed Ham', '{"sweet": 5, "spicy": 8, "earthy": 7, "floral": 5, "bitter": 6}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/cloves.jpg'),
('Nutmeg', 'nutmeg', 'The Fragrant Seed', 'The inner seed of the fruit of an evergreen tree native to the Spice Islands.', 'Béchamel sauce, eggnog, pumpkin pie, and braised meats.', 'Known to induce sleep and relieve pain in small doses.', 'Year-round', 'Classic Béchamel or Holiday Eggnog', '{"sweet": 6, "spicy": 5, "earthy": 8, "floral": 3, "bitter": 2}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/nutmeg.jpg'),
('Ginger', 'ginger', 'The Zesty Root', 'A flowering plant whose rhizome is widely used as a spice and a folk medicine.', 'Stir-fries, gingerbread, teas, and marinades.', 'Exceptional at treating nausea and soothing digestion.', 'December to February', 'Gingerbread Cookies or Thai Green Curry', '{"sweet": 4, "spicy": 7, "earthy": 6, "floral": 3, "bitter": 2}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/ginger.jpg'),
('Chili', 'chili', 'The Fiery Pod', 'Originated in Mexico, chilies were brought to Asia by Portuguese navigators in the 16th century.', 'Salsas, curries, hot sauces, and marinades.', 'High in vitamin C and capsaicin, which boosts metabolism.', 'August to November', 'Szechuan Tofu or Spicy Salsa', '{"sweet": 2, "spicy": 10, "earthy": 4, "floral": 2, "bitter": 3}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/chili.jpg'),
('Vanilla', 'vanilla', 'The Sweet Pod', 'Derived from orchids native to Mexico, it is the second most expensive spice after saffron.', 'Ice cream, cakes, custards, and perfumes.', 'Known for calming effects and rich in antioxidants.', 'August to September', 'Crème Brûlée or Vanilla Bean Ice Cream', '{"sweet": 10, "spicy": 1, "earthy": 3, "floral": 8, "bitter": 1}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/vanilla.jpg'),
('Lemongrass', 'lemongrass', 'The Citrus Grass', 'A tropical grass native to maritime Southeast Asia, bringing a bright, clean citrus flavor.', 'Tom Yum soup, curries, teas, and marinades.', 'Often traditionally used to relieve anxiety and prevent infection.', 'Year-round', 'Tom Yum Soup or Lemongrass Chicken', '{"sweet": 4, "spicy": 2, "earthy": 4, "floral": 7, "bitter": 3}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/lemongrass.jpg'),
('Curry Leaf', 'curry-leaf', 'The Aromatic Leaf', 'Leaves of the curry tree, native to India, crucial in South Indian and Sri Lankan cooking.', 'Tarka (tempering) for dals, curries, and chutneys.', 'Rich in carbazole alkaloids, known to support liver protection.', 'Year-round', 'South Indian Sambar or Lemon Rice', '{"sweet": 1, "spicy": 4, "earthy": 7, "floral": 5, "bitter": 6}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/curry-leaf.jpg'),
('Star Anise', 'star-anise', 'The Star of Flavor', 'A spice that visually looks like a star, bringing a strong licorice flavor.', 'Pho broth, Chinese five-spice powder, and braised meats.', 'The primary source of shikimic acid, a precursor to the anti-influenza drug Tamiflu.', 'March to May', 'Vietnamese Pho or Chinese Braised Pork', '{"sweet": 7, "spicy": 4, "earthy": 5, "floral": 4, "bitter": 4}', 'https://spicegarden.info/wp-content/uploads/2025/09/images/star-anise.jpg');
